/**
 * Database types — generated by `npm run db:types` after migrations are applied.
 *
 * Until then, this placeholder lets TypeScript compile. Once you've pushed
 * the migrations and linked the Supabase project:
 *
 *   npx supabase login
 *   npx supabase link --project-ref msyvlbdyynbesfkpdpip
 *   npx supabase gen types typescript --linked > lib/types/database.ts
 */
export type Database = {
  public: {
    Tables: Record<string, { Row: Record<string, unknown>; Insert: Record<string, unknown>; Update: Record<string, unknown> }>;
    Views: Record<string, { Row: Record<string, unknown> }>;
    Functions: Record<string, unknown>;
    Enums: Record<string, string>;
    CompositeTypes: Record<string, unknown>;
  };
};
